INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('real-estate-appraiser-moex-00323', 'real-estate-appraiser', 'real-estate-appraiser-moex-101-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '列御寇為伯昏無人射，引之盈貫，措杯水其肘上，發之，適矢復沓，方矢復寓。當是時，猶象人也。伯昏 無人曰：「是射之射，非不射之射也。嘗與汝登高山，履危石，臨百仞之淵，若能射乎？」於是無人遂 登高山，履危石，臨百仞之淵，背逡巡，足二分垂在外，揖御寇而進之。御寇伏地，汗流至踵。伯昏無 人曰：「夫至人者，上闚青天，下潛黃泉，揮斥八極，神氣不變。今汝怵然有恂目之志，爾於中也殆矣 夫！」《莊子．田子方》 伯昏無人揖列御寇至高山危石，列御寇為什麼「伏地，汗流至踵」？', '["驕傲", "猶豫", "恐懼", "酷熱"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:05+00:00", "source_pdf_sha1": "2d40ecc2b83f", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00324', 'real-estate-appraiser', 'real-estate-appraiser-moex-101-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '吾昔少年時，所居書室前，有竹、柏、桃、雜花，叢生滿庭，眾鳥巢其上。武陽君惡殺生，兒童婢僕， 皆不得捕取鳥雀。數年間，皆巢於低枝，其鷇可俯而窺也。又有桐花鳳四五，日翔集其間，此鳥羽毛至 為珍異難見，而能馴擾，殊不畏人。閭里間見之，以為異事。此無他，不忮之誠，信於異類也。有野老 言：「鳥巢去人太遠，則其子有蛇、鼠、狐、貍、鴟、鳶之憂；人既不殺，則自近人者，欲免此患也。」 （蘇軾〈記先夫人不殘鳥雀〉） 下列選項與上文主旨最貼近的是：', '["鳥雀近人，閭里傳為美談", "蟲鳴鳥叫，萬物靜觀皆自得", "弱肉強食、物競天擇，是自然界的生存法則", "只要以仁愛相感，雖為異類，仍能互信相依"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:05+00:00", "source_pdf_sha1": "2d40ecc2b83f", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00325', 'real-estate-appraiser', 'real-estate-appraiser-moex-101-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '張曉風〈春之懷古〉一文中：「鳥又可以開始丈量天空了。有的負責丈量天的藍度，有的負責丈量天的 透明度，有的負責用那雙翼丈量天的高度和深度，……至於所有的花，已交於□□去點數。所有的蕊， 交給□□去編冊。所有的樹，交給風去縱寵。而風，交給簷前的□□□去一一記憶、一一垂詢。」□中 的字最適合填入的選項是：', '["精靈／知了／垂楊柳", "蝴蝶／蜜蜂／老風鈴", "蜜蜂／蜻蜓／紡織娘", "露水／少女／含羞草"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:05+00:00", "source_pdf_sha1": "2d40ecc2b83f", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00326', 'real-estate-appraiser', 'real-estate-appraiser-moex-101-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '從植物富裕中的擴張性，我們看到一項感人的事實。植物絕對不奢侈，它得到好環境，並不用來驕恣放 肆，卻全部用來盡其最大可能的繁殖責任，盡其最大可能多枝多蔓，而後開出最大限的花數，結出最大 限的種子數。這一點跟人類大大不相同。……（陳冠學〈植物之性〉） 從上述段落「這一點跟人類大大不相同」之後，推測該文接下來要表達人類的狀況應該是：', '["人類若得到好環境，常視為天命", "人類若能以植物為師，就不致有絕滅危機", "人類往往窮奢極侈，盡情揮霍，終至身家敗亡", "人類在追求物質上會有自覺，因而容易得到滿足感"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:05+00:00", "source_pdf_sha1": "2d40ecc2b83f", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00327', 'real-estate-appraiser', 'real-estate-appraiser-moex-101-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '泰戈爾在《漂鳥集》有言：「在缸裡的水是透明的；在海中的水卻黝黑。微小的真理有清晰的言辭，偉 大的真理卻只是偉大的沉默。」 下列選項何者與上文觀點不相符？', '["大音希聲，大象無形", "書不盡言，言不盡意", "道可道，非常道；名可名，非常名", "四象不形，則大象無以暢；五音不聲，則大音無以至"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:05+00:00", "source_pdf_sha1": "2d40ecc2b83f", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00328', 'real-estate-appraiser', 'real-estate-appraiser-moex-101-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '隗曰：「臣聞古之人君有以千金求千里馬者，三年不能得。涓人言於君曰：『請求之。』君遣之，三月， 得千里馬，馬已死，買其骨五百金。反以報君，君大怒，曰：『所求者生馬，安用死馬，捐五百金！』 涓人對曰：『死馬且市之五百金，況生馬乎？天下必以王為能市馬，馬今至矣！』於是，不期年千里馬 至者二。今王誠欲必致士，請從隗始。隗且見事，況賢於隗者乎？豈遠千里哉？」於是，昭王為隗築宮 而師之。（《新序．雜事》） 上文所要凸顯的是：', '["君臣上下相賊的詭詐", "謀士巧辯得官的伎倆", "君主充分授權的胸襟", "謀士為君招賢的智慧"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:05+00:00", "source_pdf_sha1": "2d40ecc2b83f", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00329', 'real-estate-appraiser', 'real-estate-appraiser-moex-101-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '沈志方〈夜讀棋譜〉：「我也是一局殺聲隱隱的棋譜／骨骼血液為局，我也有／愛憎、義利、勇怯……／ 這些不共戴天的將帥／盤據體內，夜深時搏殺慘烈／所以每天清晨疼醒，我常是／不知為什麼含淚起 的／馬砲士卒，攜帶各種武器／奔馳在上班下班的小小棋盤上／苦苦計算得失勝敗」。 下列文句何者較接近本詩寓意？', '["棋局已殘，吾人將老，欲不哭泣也得乎（劉鶚《老殘遊記》）", "見說長安如弈，不忍問君蹤，水驛山郵都未識，夢囘何處覓（鄭文焯〈謁金門〉）", "涉世如局戲，……大都要勝之心，一般所爭者，算有長短，知有巧拙（袁宏道〈答友人〉）", "聞道長安似弈棋，百年世事不勝悲。王侯第宅皆新主，文武衣冠異昔時（杜甫〈秋興〉）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:05+00:00", "source_pdf_sha1": "2d40ecc2b83f", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00330', 'real-estate-appraiser', 'real-estate-appraiser-moex-101-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '呂蒙正相公不喜記人過。初參知政事，入朝堂，有朝士于簾內指之曰：「是小子亦參政耶？」蒙正佯為 不聞而過之。其同列怒，令詰其官位、姓名，蒙正遽止之。罷朝，同列猶不能平，悔不窮問。蒙正曰： 「一知其姓名，則終身不能復忘，固不如無知也。不問之，何損？」 根據上文，下列對呂蒙正的評論何者最適切？', '["以友輔仁", "寬宏大量", "舉直錯諸枉", "過則勿憚改"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:05+00:00", "source_pdf_sha1": "2d40ecc2b83f", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00331', 'real-estate-appraiser', 'real-estate-appraiser-moex-101-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '「簡能而任之，擇善而從之，則智者盡其謀，勇者竭其力，仁者播其惠，信者效其忠。」（魏徵〈諫太 宗十思疏〉） 根據上文，可以知道魏徵以下列那一項是一個領導決策者必須具備的核心能力？', '["聰明睿智，善於謀事", "言出必行，忠君愛民", "武勇過人，威震天下", "知人善任，從善如流"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:05+00:00", "source_pdf_sha1": "2d40ecc2b83f", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00332', 'real-estate-appraiser', 'real-estate-appraiser-moex-101-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '人之良，孰願為盜也，由長民者失於教養，凍餒之極，遂至於此，要非其得已也。嘗潛體其然，使父饑 母寒，妻子慍見，徵負旁午，疹疫交攻，萬死一生，朝不逮暮，於斯時也，見利而不回者，能幾何人？ 其或因而攘竊，不原其情，輒置諸理，嬰笞關木，彼固無辭。然百需叢身，孰明其不獲已哉？古人謂： 「上失其道，民散久矣。如得其情，則哀矜而勿喜。」嗚呼！人能以是論囚，雖欲慘酷，亦必有所不忍矣。 下列那一選項與本文意旨最接近？', '["矜孤養老，邦家之大政", "安時興化，貴在慎獄存恕", "明君治難於其易，去惡於其微", "仁君在上，則海內無餒殍之人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:05+00:00", "source_pdf_sha1": "2d40ecc2b83f", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL)
